def solve():
    import sys
    input_data = sys.stdin.read().split()
    idx = 0
    t = int(input_data[idx]); idx += 1

    def smallest_geq(n_str, digits):
        # Find smallest number >= n_str using only digits in `digits` (sorted list), no leading zeros
        digits = sorted(digits)
        nonzero_digits = [d for d in digits if d != '0']
        if not nonzero_digits:
            return None

        n = len(n_str)

        # Try same length first
        result = try_length(n_str, digits, nonzero_digits)
        if result is not None:
            return result

        # Try length n+1
        return nonzero_digits[0] + digits[0] * n

    def try_length(n_str, digits, nonzero_digits):
        # Try to find smallest number of same length >= n_str
        n = len(n_str)
        chosen = []

        def backtrack(pos, tight):
            if pos == n:
                return ''.join(chosen)

            start_digit = n_str[pos] if tight else '0'
            available = [d for d in digits if d >= start_digit]
            if pos == 0:
                available = [d for d in available if d != '0']

            for d in available:
                chosen.append(d)
                new_tight = tight and (d == n_str[pos])
                if new_tight:
                    res = backtrack(pos + 1, True)
                    if res is not None:
                        return res
                else:
                    # Fill rest with min digit
                    min_d = digits[0]
                    return ''.join(chosen) + min_d * (n - pos - 1)
                chosen.pop()

            return None

        return backtrack(0, True)

    results = []
    for _ in range(t):
        n = int(input_data[idx]); idx += 1
        k = int(input_data[idx]); idx += 1
        n_str = str(n)

        best = None
        all_digits = [str(i) for i in range(10)]

        from itertools import combinations
        for size in range(1, k+1):
            for combo in combinations(all_digits, size):
                digits = list(combo)
                nonzero = [d for d in digits if d != '0']
                if not nonzero:
                    continue
                res = smallest_geq(n_str, digits)
                if res is not None:
                    val = int(res)
                    if best is None or val < best:
                        best = val

        results.append(best)

    print('\n'.join(map(str, results)))

solve()
